<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;
class ShopSale extends Model{protected $fillable=['shop_id','character_id','item_id','item_instance_id','character_item_id_snapshot','source_type','quantity_sold','unit_gold','total_gold','idempotency_key','sold_at','metadata'];protected $casts=['shop_id'=>'integer','character_id'=>'integer','item_id'=>'integer','item_instance_id'=>'integer','character_item_id_snapshot'=>'integer','quantity_sold'=>'integer','unit_gold'=>'integer','total_gold'=>'integer','sold_at'=>'immutable_datetime','metadata'=>'array'];public function shop(){return$this->belongsTo(Shop::class);}public function character(){return$this->belongsTo(Character::class);}public function item(){return$this->belongsTo(Item::class);}public function itemInstance(){return$this->belongsTo(ItemInstance::class);}}
